<script setup lang="ts">
import { Head, Link } from '@inertiajs/vue3';
import { Camera, ChevronLeft, Save } from '@lucide/vue';
import { computed, onMounted, ref } from 'vue';
import AppShell from '../../Layouts/AppShell.vue';
const profile=ref<any>();const sports=ref<any[]>([]);const photo=ref<File|null>(null);const preview=ref('');const saving=ref(false);const notice=ref('');const error=ref('');
const form=ref<any>({name:'',role:'athlete',date_of_birth:'',gender:'',bio:'',country:'ZA',province:'',city:'',locality:'',township:'',is_public:true,is_available:false,interested_sports:[],sport_id:'',position_id:'',club_name:'',playing_level:'',dominant_side:'',height_cm:'',weight_kg:''});
const positions=computed(()=>sports.value.find(s=>String(s.id)===form.value.sport_id)?.positions??[]);const csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'';
const api=async(url:string,o:RequestInit={})=>{const r=await fetch(url,{...o,credentials:'same-origin',headers:{Accept:'application/json','X-CSRF-TOKEN':csrf(),...(o.body instanceof FormData?{}:{'Content-Type':'application/json'})}});const p=await r.json();if(!r.ok)throw new Error(p.message??Object.values(p.errors??{}).flat().join(' '));return p.data??p};
const fill=(p:any)=>{profile.value=p;form.value={...form.value,name:p.name??'',role:p.roles?.[0]??'athlete',date_of_birth:p.date_of_birth??'',gender:p.gender??'',bio:p.bio??'',country:p.location?.country??'ZA',province:p.location?.province??'',city:p.location?.city??'',locality:p.location?.locality??'',township:p.location?.township??'',is_available:!!p.is_available,interested_sports:p.fan?.interested_sports??[],sport_id:String(p.athlete?.sport?.id??''),position_id:String(p.athlete?.position?.id??''),club_name:p.athlete?.club_name??'',playing_level:p.athlete?.playing_level??'',dominant_side:p.athlete?.dominant_side??'',height_cm:p.athlete?.height_cm??'',weight_kg:p.athlete?.weight_kg??''}};
const pick=(f?:File)=>{if(f){photo.value=f;preview.value=URL.createObjectURL(f)}};const toggleSport=(name:string)=>form.value.interested_sports.includes(name)?form.value.interested_sports=form.value.interested_sports.filter((s:string)=>s!==name):form.value.interested_sports.push(name);
const save=async()=>{saving.value=true;notice.value='';error.value='';try{if(photo.value){const b=new FormData();b.append('photo',photo.value);profile.value.images.profile=(await api('/api/v1/profile/photo',{method:'POST',body:b})).url}await api('/api/v1/profile/role',{method:'PATCH',body:JSON.stringify({role:form.value.role})});await api('/api/v1/profile',{method:'PATCH',body:JSON.stringify({name:form.value.name,date_of_birth:form.value.date_of_birth||null,gender:form.value.gender||null,bio:form.value.bio||null,country:form.value.country||null,province:form.value.province||null,city:form.value.city||null,locality:form.value.locality||null,township:form.value.township||null,is_public:form.value.is_public,is_available:form.value.is_available})});if(form.value.role==='athlete')await api('/api/v1/profile/athlete',{method:'PATCH',body:JSON.stringify({sport_id:+form.value.sport_id||null,position_id:+form.value.position_id||null,club_name:form.value.club_name||null,playing_level:form.value.playing_level||null,dominant_side:form.value.dominant_side||null,height_cm:+form.value.height_cm||null,weight_kg:+form.value.weight_kg||null})});if(form.value.role==='fan')await api('/api/v1/onboarding/fan-interests',{method:'PUT',body:JSON.stringify({interested_sports:form.value.interested_sports})});fill(await api('/api/v1/profile'));notice.value='Profile updated successfully.'}catch(e:any){error.value=e.message}finally{saving.value=false}};
onMounted(async()=>{const[p,s]=await Promise.all([api('/api/v1/profile'),api('/api/v1/sports')]);sports.value=s;fill(p)});
</script>
<template><Head title="Edit Profile"/><AppShell><main class="profile-edit-page"><header><Link href="/profile"><ChevronLeft/>Back to profile</Link><h1>Edit profile</h1><p>Update your identity, location and sporting details.</p></header><form v-if="profile" @submit.prevent="save"><aside><div class="edit-avatar"><img v-if="preview||profile.images?.profile" :src="preview||profile.images.profile"/><span v-else>{{form.name.slice(0,2).toUpperCase()}}</span><label><Camera/><input hidden type="file" accept="image/jpeg,image/png,image/webp" @change="pick(($event.target as HTMLInputElement).files?.[0])"/></label></div><h2>{{form.name}}</h2><small>@{{profile.slug}}</small><p>{{profile.completeness}}% complete</p><label class="edit-toggle"><span>Public profile</span><input v-model="form.is_public" type="checkbox"/></label><label class="edit-toggle"><span>Available for opportunities</span><input v-model="form.is_available" type="checkbox"/></label></aside><div class="edit-sections"><section><h2>Personal information</h2><div class="edit-fields"><label>Full name<input v-model="form.name" required/></label><label>Primary role<select v-model="form.role"><option v-for="r in ['athlete','fan','coach','scout','agent','club','academy','business','sponsor']" :key="r">{{r}}</option></select></label><label>Date of birth<input v-model="form.date_of_birth" type="date"/></label><label>Gender<select v-model="form.gender"><option value="">Prefer not to say</option><option>male</option><option>female</option><option>non-binary</option></select></label><label class="wide">Description <small>{{form.bio.length}}/1000</small><textarea v-model="form.bio" maxlength="1000"/></label></div></section><section v-if="form.role==='athlete'"><h2>Sporting details</h2><div class="edit-fields"><label>Sport<select v-model="form.sport_id"><option value="">Select sport</option><option v-for="s in sports" :key="s.id" :value="String(s.id)">{{s.name}}</option></select></label><label>Position<select v-model="form.position_id"><option value="">Select position</option><option v-for="p in positions" :key="p.id" :value="String(p.id)">{{p.name}}</option></select></label><label>Club or academy<input v-model="form.club_name"/></label><label>Playing level<input v-model="form.playing_level"/></label><label>Dominant side<select v-model="form.dominant_side"><option value="">Select</option><option>left</option><option>right</option><option>both</option></select></label><label>Height (cm)<input v-model="form.height_cm" type="number"/></label><label>Weight (kg)<input v-model="form.weight_kg" type="number" step=".1"/></label></div></section><section><h2>Location</h2><div class="edit-fields"><label>Country code<input v-model="form.country" maxlength="2"/></label><label>Province<input v-model="form.province"/></label><label>City<input v-model="form.city"/></label><label>Locality<input v-model="form.locality"/></label></div></section><p v-if="error" class="edit-message error">{{error}}</p><p v-if="notice" class="edit-message success">{{notice}}</p><div class="edit-actions"><Link href="/profile">Cancel</Link><button :disabled="saving"><Save/>{{saving?'Saving…':'Save profile'}}</button></div></div></form></main></AppShell></template>
